SELECT players.name, historical_performance.total_games_played
FROM players
INNER JOIN historical_performance ON players.player_id = historical_performance.player_id;

SELECT player_id, week, points, projection, difference, rank 
FROM fantasy_points 
WHERE week = 6 AND points > 25 AND projection > 20;

SELECT name
FROM players
WHERE player_id NOT IN (SELECT player_id FROM fantasy_points);

SELECT player_id
FROM historical_performance
WHERE avg_yards > 6 AND total_fumbles > 10;

SELECT player_id, injury_type, injury_status
FROM injury_reports
WHERE injury_type = 'Hamstring Strain' AND injury_status = 'Active';
